<script setup lang="ts">
import {Head,Link,useForm} from '@inertiajs/vue3';import{Eye,LockKeyhole,Mail,Play}from'@lucide/vue';import{onMounted,onUnmounted,ref}from'vue';import BrandLogo from '../../Components/BrandLogo.vue';
const form=useForm({login:'',password:'',remember:false}),followers=ref(1240),likes=ref(8640),views=ref(24600);let ticker:ReturnType<typeof setInterval>;const submit=()=>form.post('/login'),compact=(n:number)=>new Intl.NumberFormat('en',{notation:'compact',maximumFractionDigits:1}).format(n);onMounted(()=>ticker=setInterval(()=>{followers.value+=Math.ceil(Math.random()*3);likes.value+=Math.ceil(Math.random()*9);views.value+=Math.ceil(Math.random()*24)},850));onUnmounted(()=>clearInterval(ticker));
